foreach ($pair in @(
  @{n='neg+ip\user';c=$cred;a='Negotiate'},
  @{n='neg+.\user';c=$credDot;a='Negotiate'},
  @{n='neg+bare';c=$credBare;a='Negotiate'},
  @{n='basic+ip\user';c=$cred;a='Basic'},
  @{n='basic+bare';c=$credBare;a='Basic'}
)) {
  try {
    $r = Invoke-Command -ComputerName $ip -Credential $pair.c -Authentication $pair.a -ScriptBlock { "$env:COMPUTERNAME|$env:USERNAME" } -ErrorAction Stop
    Write-Host "SUCCESS $($pair.n): $r"
  } catch {
    $msg = $_.Exception.Message
    if ($msg.Length -gt 180) { $msg = $msg.Substring(0,180) }
    Write-Host "FAIL $($pair.n): $msg"
  }
}

