# Write a one-shot fix for TokenFilterPolicy via admin share + schtasks
$fixBat = @"
@echo off
reg add "HKLM\SOFTWARE\Microsoft\Windows\CurrentVersion\Policies\System" /v LocalAccountTokenFilterPolicy /t REG_DWORD /d 1 /f
powershell -NoProfile -Command "Restart-Service WinRM -Force"
"@
$remotePath = "\\$ip\C$\Windows\Temp\fix_winrm_token.bat"
Set-Content -Path $remotePath -Value $fixBat -Encoding ASCII -Force
Write-Host "wrote $remotePath"
cmd /c "schtasks /s $ip /u $ip\usr1cv8 /p 1111 /create /tn FixWinRMToken /tr C:\Windows\Temp\fix_winrm_token.bat /sc once /st 00:00 /ru SYSTEM /f" 2>&1
cmd /c "schtasks /s $ip /u $ip\usr1cv8 /p 1111 /run /tn FixWinRMToken" 2>&1
Start-Sleep 3
cmd /c "schtasks /s $ip /u $ip\usr1cv8 /p 1111 /query /tn FixWinRMToken /v /fo LIST" 2>&1 | Select-String -Pattern 'Status|Last Run|Result|Task Name'

