$ip='26.248.72.177'
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
$ErrorActionPreference='Continue'
function L($m){ Write-Output $m }

L "=== HOST ==="
L "$env:COMPUTERNAME | $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"

L "`n=== FRONTOL / ATOL SERVICES ==="
Get-Service | Where-Object { $_.Name -match 'atol|frontol|lic|fdsvc|hasp|sentinel|guardant' -or $_.DisplayName -match 'ATOL|Frontol|Licen|HASP|Sentinel|Guardant' } |
  Sort-Object Status,Name | ForEach-Object { L "$($_.Status)  $($_.Name)  $($_.DisplayName)" }

L "`n=== FRONTOL PROCESSES ==="
Get-Process | Where-Object { $_.Name -match 'frontol|atol|lic|fdsvc|hasp|sentinel' } |
  ForEach-Object { L "$($_.Name) pid=$($_.Id) sess=$($_.SessionId)" }

L "`n=== INSTALL PATHS ==="
@(
  'C:\Program Files (x86)\ATOL',
  'C:\Program Files\ATOL',
  'C:\ProgramData\ATOL',
  'C:\БД Frontol',
  'C:\Frontol'
) | ForEach-Object {
  if (Test-Path $_) { L "EXISTS $_" } else { L "MISS $_" }
}

L "`n=== FRONTOL VERSION / EXES ==="
Get-ChildItem 'C:\Program Files (x86)\ATOL','C:\Program Files\ATOL' -Recurse -Include '*.exe','*.dll' -EA SilentlyContinue |
  Where-Object { $_.Name -match 'Frontol|Lic|Guard|HASP|Sentinel' } |
  Select-Object -First 40 FullName, Length, LastWriteTime |
  ForEach-Object { L "$($_.LastWriteTime.ToString('yyyy-MM-dd')) $($_.Length) $($_.FullName)" }

L "`n=== LICENSE-RELATED FILES ==="
$roots = @(
  'C:\ProgramData\ATOL',
  'C:\Program Files (x86)\ATOL',
  'C:\Program Files\ATOL',
  'C:\Users'
)
foreach ($r in $roots) {
  if (-not (Test-Path $r)) { continue }
  Get-ChildItem $r -Recurse -EA SilentlyContinue |
    Where-Object { -not $_.PSIsContainer -and ($_.Extension -match '\.(lic|key|license|licx)$' -or $_.Name -match 'licen|лиценз|activation|активац|serial|ключ') } |
    Select-Object -First 50 FullName, Length, LastWriteTime |
    ForEach-Object { L "LIC $($_.LastWriteTime.ToString('yyyy-MM-dd HH:mm')) $($_.Length) $($_.FullName)" }
}

L "`n=== FRONTOL.INI ==="
$inis = @(
  'C:\ProgramData\ATOL\Frontol6\Settings\Frontol.ini',
  'C:\Program Files (x86)\ATOL\Frontol6\BIN\Frontol.ini'
)
foreach ($i in $inis) {
  if (Test-Path $i) {
    L "--- $i ---"
    Get-Content $i -EA SilentlyContinue | Select-Object -First 80 | ForEach-Object { L $_ }
  }
}

L "`n=== RECENT LOGS (Frontol/ATOL, last 20) ==="
Get-ChildItem 'C:\ProgramData\ATOL','C:\Program Files (x86)\ATOL' -Recurse -Include '*.log','*.txt' -EA SilentlyContinue |
  Where-Object { $_.LastWriteTime -gt (Get-Date).AddDays(-14) -and $_.Length -lt 20MB } |
  Sort-Object LastWriteTime -Descending |
  Select-Object -First 25 |
  ForEach-Object { L "$($_.LastWriteTime.ToString('yyyy-MM-dd HH:mm')) $($_.Length) $($_.FullName)" }
}

