$con = 'C:\Program Files (x86)\ATOL\LicManager\LicenseManager_con.exe'
if (Test-Path $con) {
  & $con /? 2>&1 | ForEach-Object { L $_ }
  & $con -h 2>&1 | ForEach-Object { L $_ }
  & $con help 2>&1 | ForEach-Object { L $_ }
