Get-ChildItem 'C:\Users\Public\Desktop','C:\Users\usr1cv8\Desktop' -EA SilentlyContinue | ForEach-Object { L "ALT $($_.FullName)" }
}

$ip='26.248.72.177'
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
$ErrorActionPreference='Continue'
function L($m){ Write-Output $m }

# Read log as UTF-8 / default OEM properly
$lg = 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvc.log'
$bytes = [IO.File]::ReadAllBytes($lg)
# try last portion decode as Windows-1251
$enc1251 = [Text.Encoding]::GetEncoding(1251)
$text = $enc1251.GetString($bytes)
$lines = $text -split "`r?`n"
L "=== LAST LICENSE STATUS LINES (cp1251) ==="
$lines | Select-String -Pattern 'получен|ошибк|Licenses|License server|LMRequest|активац|привяз|E0ALY|3DWQC|CN4QC|Y1KPT|6KG43|8AFTD' |
  Select-Object -Last 80 | ForEach-Object { L $_.Line }

L "`n=== AtolLicSvc.ini ==="
Get-Content 'C:\ProgramData\ATOL\AtolLicSvc\AtolLicSvc.ini' -Encoding Default | ForEach-Object { L $_ }

L "`n=== LicenseManager_con probes ==="
$con = 'C:\Program Files (x86)\ATOL\LicManager\LicenseManager_con.exe'
Push-Location 'C:\Program Files (x86)\ATOL\LicManager'
foreach ($args in @(
  @('--help'),
  @('/help'),
  @('-help'),
  @('list'),
  @('/list'),
  @('-list'),
  @('getLicenseList'),
  @('/getLicenseList'),
  @('localhost','756'),
  @('-host','localhost','-port','756','-list')
)) {
  L ("CMD: " + ($args -join ' '))
  try {
    $out = & $con @args 2>&1 | Out-String
    if ($out.Trim()) { L $out.Trim().Substring(0, [Math]::Min(800, $out.Trim().Length)) }
  } catch { L "ERR $($_.Exception.Message)" }
}
Pop-Location

L "`n=== TCP 756 local ==="
try {
  $c = New-Object Net.Sockets.TcpClient
  $c.Connect('127.0.0.1',756)
  L "port 756 open=$($c.Connected)"
  $c.Close()
} catch { L "port 756 FAIL: $($_.Exception.Message)" }

L "`n=== HTTP/API on 756? ==="
try {
  $r = Invoke-WebRequest -Uri 'http://127.0.0.1:756/' -UseBasicParsing -TimeoutSec 5
  L "HTTP $($r.StatusCode) len=$($r.RawContentLength)"
  L $r.Content.Substring(0,[Math]::Min(500,$r.Content.Length))
} catch { L "HTTP fail: $($_.Exception.Message)" }

# Try common LM JSON API
foreach ($u in @(
  'http://127.0.0.1:756/getLicenseList',
  'http://127.0.0.1:756/api/getLicenseList',
  'http://127.0.0.1:756/licenses'
)) {
  try {
    $r = Invoke-WebRequest -Uri $u -UseBasicParsing -TimeoutSec 5
    L "OK $u -> $($r.StatusCode) $($r.Content.Substring(0,[Math]::Min(300,$r.Content.Length)))"
  } catch { L "FAIL $u : $($_.Exception.Message)" }
}

L "`n=== Peek .lic files (text headers) ==="
Get-ChildItem 'C:\ProgramData\ATOL\AtolLicSvc\license\*.lic' | ForEach-Object {
  L "--- $($_.Name) ---"
  $raw = [IO.File]::ReadAllBytes($_.FullName)
  $t = $enc1251.GetString($raw)
  # show printable first lines / keys
  ($t -split "`r?`n" | Select-Object -First 15) | ForEach-Object { L $_ }
}
}

$ip='26.248.72.177'
$sec = ConvertTo-SecureString '1111' -AsPlainText -Force
$cred = New-Object System.Management.Automation.PSCredential("$ip\usr1cv8", $sec)
Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
