  Select-Object -Last 100 | ForEach-Object { L $_ }

L "`n=== Any mention of E0ALY ==="
$lines | Where-Object { $_ -match 'E0ALY' } | Select-Object -Last 30 | ForEach-Object { L $_ }

L "`n=== Connectivity lm.frontol.ru ==="
try {
  $r = Resolve-DnsName lm.frontol.ru -EA Stop | Select-Object -First 3
  $r | ForEach-Object { L "$($_.Type) $($_.IPAddress)$($_.NameHost)" }
} catch { L "DNS fail: $($_.Exception.Message)" }
try {
  $t = Test-NetConnection lm.frontol.ru -Port 443 -WarningAction SilentlyContinue
  L "TCP443=$($t.TcpTestSucceeded) Ping=$($t.PingSucceeded)"
} catch { L "TNC fail: $($_.Exception.Message)" }
try {
  $w = Invoke-WebRequest 'https://lm.frontol.ru' -UseBasicParsing -TimeoutSec 15
  L "HTTPS status=$($w.StatusCode)"
} catch { L "HTTPS: $($_.Exception.Message)" }

L "`n=== Recent downloads with license codes ==="
Get-ChildItem 'C:\Users\POS1\Downloads','C:\Users\Public','C:\Temp','C:\Windows\Temp' -Recurse -EA SilentlyContinue |
  Where-Object { -not $_.PSIsContainer -and ($_.Extension -match '\.(lic|key|txt|pdf|zip)$' -or $_.Name -match 'licen|лиц|Frontol|E0ALY|активац') -and $_.LastWriteTime -gt (Get-Date).AddDays(-30) } |
  Sort-Object LastWriteTime -Descending | Select-Object -First 30 |
  ForEach-Object { L "$($_.LastWriteTime.ToString('yyyy-MM-dd HH:mm')) $($_.Length) $($_.FullName)" }

