  Where-Object { $_.ProviderName -match 'ATOL|Frontol|Lic' -or $_.Message -match 'лиц|licen|Frontol|AtolLic' } |
  Select-Object -First 20 TimeCreated, ProviderName, Id, LevelDisplayName |
  ForEach-Object { L "$($_.TimeCreated) $($_.ProviderName) id=$($_.Id) $($_.LevelDisplayName)" }
}

