Invoke-Command -ComputerName $ip -Credential $cred -Authentication Negotiate -ScriptBlock {
  function W($m){ Write-Output $m }
  $dir = 'C:\Program Files (x86)\ATOL\LicManager'
  $con = Join-Path $dir 'LicenseManager_con.exe'
  Set-Location $dir

  W '=== platforms ==='
  Get-ChildItem (Join-Path $dir 'platforms') -EA SilentlyContinue | ForEach-Object { W $_.Name }

  function Invoke-Con([string]$arguments, [hashtable]$extraEnv=@{}) {
    $psi = New-Object System.Diagnostics.ProcessStartInfo
    $psi.FileName = $con
    $psi.Arguments = $arguments
    $psi.RedirectStandardOutput = $true
    $psi.RedirectStandardError = $true
    $psi.UseShellExecute = $false
    $psi.CreateNoWindow = $true
    $psi.WorkingDirectory = $dir
    $psi.EnvironmentVariables['QT_PLUGIN_PATH'] = $dir
    $psi.EnvironmentVariables['QT_QPA_PLATFORM_PLUGIN_PATH'] = (Join-Path $dir 'platforms')
    $psi.EnvironmentVariables['QT_QPA_PLATFORM'] = 'windows'
    $psi.EnvironmentVariables['QT_LOGGING_RULES'] = '*=true'
    foreach ($k in $extraEnv.Keys) { $psi.EnvironmentVariables[$k] = $extraEnv[$k] }
    # capture crash
    $psi.EnvironmentVariables['PATH'] = "$dir;" + $psi.EnvironmentVariables['PATH']
    try {
      $p = [Diagnostics.Process]::Start($psi)
      $out = $p.StandardOutput.ReadToEnd()
      $err = $p.StandardError.ReadToEnd()
      $p.WaitForExit(30000) | Out-Null
      W "CMD=$arguments exit=$($p.ExitCode)"
      if ($out) { W "OUT=$out" }
      if ($err) { W "ERR=$err" }
    } catch {
      W "FAIL $arguments :: $($_.Exception.Message)"
