        if ($t2 -and $t2.Trim().Length -gt 0) { $all.Add("  [$t2]") }
        return $true
      }, [IntPtr]::Zero) | Out-Null
    }
    return $true
  }, [IntPtr]::Zero) | Out-Null
  W ("Window entries: " + $all.Count)
  $all | Select-Object -First 100 | ForEach-Object { W $_ }

  # Capture screenshot of console session if possible via BitBlt - hard from session 0
  # Instead write a small helper that runs IN session 1 and dumps UI Automation / window text to file
  $probe = @'
Add-Type @"
using System;
using System.Text;
using System.Runtime.InteropServices;
using System.Collections.Generic;
public class W5 {
  public delegate bool EnumProc(IntPtr hWnd, IntPtr lParam);
  [DllImport("user32.dll")] public static extern bool EnumWindows(EnumProc cb, IntPtr l);
  [DllImport("user32.dll")] public static extern bool EnumChildWindows(IntPtr h, EnumProc cb, IntPtr l);
  [DllImport("user32.dll")] public static extern uint GetWindowThreadProcessId(IntPtr h, out uint p);
  [DllImport("user32.dll", CharSet=CharSet.Unicode)] public static extern int GetWindowText(IntPtr h, StringBuilder s, int n);
  [DllImport("user32.dll")] public static extern bool IsWindowVisible(IntPtr h);
}
"@
$out = New-Object Collections.Generic.List[string]
$fp = Get-Process Frontol -EA SilentlyContinue | Select-Object -First 1
if (-not $fp) { "NO FRONTOL" | Set-Content C:\Windows\Temp\frontol_ui.txt -Encoding UTF8; return }
$tid = [uint32]$fp.Id
[W5]::EnumWindows({
  param($h,$l)
  [uint32]$p=0; [void][W5]::GetWindowThreadProcessId($h,[ref]$p)
  if ($p -eq $tid) {
    $sb=New-Object Text.StringBuilder 2048
    [void][W5]::GetWindowText($h,$sb,2048)
    $out.Add("TOP vis=$([W5]::IsWindowVisible($h)) [$($sb.ToString())]")
    [W5]::EnumChildWindows($h,{
      param($ch,$l2)
      $s2=New-Object Text.StringBuilder 2048
      [void][W5]::GetWindowText($ch,$s2,2048)
      $t=$s2.ToString()
      if ($t.Trim()) { $out.Add("  $t") }
      return $true
    },[IntPtr]::Zero)|Out-Null
  }
  return $true
},[IntPtr]::Zero)|Out-Null
$out | Set-Content C:\Windows\Temp\frontol_ui.txt -Encoding UTF8
'@
  Set-Content 'C:\Windows\Temp\probe_frontol_ui.ps1' -Value $probe -Encoding UTF8
  Unregister-ScheduledTask -TaskName 'ProbeFrontolUI' -Confirm:$false -EA SilentlyContinue
  $action = New-ScheduledTaskAction -Execute 'powershell.exe' -Argument '-NoProfile -ExecutionPolicy Bypass -File C:\Windows\Temp\probe_frontol_ui.ps1'
  $principal = New-ScheduledTaskPrincipal -UserId 'POS' -LogonType Interactive -RunLevel Highest
  Register-ScheduledTask -TaskName 'ProbeFrontolUI' -Action $action -Principal $principal -Force | Out-Null
  Start-ScheduledTask -TaskName 'ProbeFrontolUI'
  Start-Sleep 4
  if (Test-Path 'C:\Windows\Temp\frontol_ui.txt') {
    W '=== UI from session 1 ==='
    Get-Content 'C:\Windows\Temp\frontol_ui.txt' -Encoding UTF8 | ForEach-Object { W $_ }
  } else { W 'no ui file' }
}
